using HTX586CONTRACT.Domain.Contracts; using Microsoft.EntityFrameworkCore; using Microsoft.EntityFrameworkCore.Metadata.Builders;
namespace HTX586CONTRACT.Infrastructure.Persistence.Configurations;
public sealed class ContractTypeConfiguration:IEntityTypeConfiguration<ContractType>{public void Configure(EntityTypeBuilder<ContractType>b){b.ToTable("ContractTypes");b.HasKey(x=>x.Id);b.Property(x=>x.Code).HasMaxLength(30).IsRequired();b.Property(x=>x.Name).HasMaxLength(200).IsRequired();b.Property(x=>x.Description).HasMaxLength(1000);b.Property(x=>x.RowVersion).IsRowVersion();b.HasIndex(x=>x.Code).IsUnique().HasFilter("[IsDeleted] = 0").HasDatabaseName("UX_ContractTypes_Code");b.HasIndex(x=>new{x.IsActive,x.Name}).HasDatabaseName("IX_ContractTypes_Active_Name");b.HasQueryFilter(x=>!x.IsDeleted);}}
